<?phpnamespace PC_CPQ\Helpers;if ( ! defined( 'ABSPATH' ) )	exit;class Access{	static public $domain_whitelist;	static public $email_whitelist;	static public function set_access()	{		self::$domain_whitelist = self::get_field( 'domain_whitelist' );		self::$email_whitelist = self::get_field( 'email_whitelist' );	}	static private function get_field( $field )	{		if ( ! function_exists( 'get_field' ) ) {			return null;		}				$value = \get_field( $field, 'option' );		if ( $value != '' ) {			$value = explode( "\n", $value );			$value = array_map( 'self::sanitize_string', $value );		}		return $value;	}	static public function is_whitelisted( $email )	{		$email = self::sanitize_string( $email );		return ( self::domain_is_whitelisted( $email ) || self::email_is_whitelisted( $email ) ) ? 'Yes' : 'No';	}	static private function domain_is_whitelisted( $email )	{		$whitelisted = false;		if ( filter_var( $email, FILTER_VALIDATE_EMAIL ) ) {			$email_parts = explode( '@', $email );			$domain = array_pop( $email_parts );			if ( is_array( self::$domain_whitelist ) && ! empty( self::$domain_whitelist ) && in_array( $domain, self::$domain_whitelist ) ) {				$whitelisted = true;			}		}		return $whitelisted;	}	static private function email_is_whitelisted( $email )	{		$whitelisted = false;		if ( filter_var( $email, FILTER_VALIDATE_EMAIL ) ) {			if ( is_array( self::$email_whitelist ) && ! empty( self::$email_whitelist ) && in_array( $email, self::$email_whitelist ) ) {				$whitelisted = true;			}		}		return $whitelisted;	}	static private function sanitize_string( $string )	{		$string = trim( $string );		$string = strtolower( $string );		return $string;	}}Access::set_access();